def test_brute_force_lockout():
    for i in range(6):
        client.post('/api/login', json={'user': 'admin', 'pass': 'wrong'})
    r = client.post('/api/login', json={'user': 'admin', 'pass': 'wrong'})
    assert r.status_code == 429

